# Recolorable inline SVG logos for the partners marquee.
# Real vector marks (Wikimedia Commons / SimpleIcons, PD-textlogo) where a clean one exists;
# honest bold-sans text wordmarks otherwise (most gate-industry brands publish no clean SVG).
# All use fill="currentColor" so one CSS color drives the whole wall.

def _text(name, label, w=150, fs=30, weight=800, ls=1):
    return (f'<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 {w} 40" fill="currentColor" '
            f'role="img" aria-label="{label}"><text x="{w//2}" y="30" text-anchor="middle" '
            f'font-family="\'Plus Jakarta Sans\',Arial,sans-serif" font-size="{fs}" '
            f'font-weight="{weight}" letter-spacing="{ls}">{name}</text></svg>')

